#include<bits/stdc++.h>
using namespace std;

int main(){
    int a,b,ans=0;
    cin>>a>>b;
    for(int i=a;i<=b;i++){
        string a=to_string(i);
        bool b[105]={0};
        for(int i=0;i<a.size();i++){
            if(!b[a[i]-'0']&&(a[i]-'0'<a.size())){
                b[a[i]-'0']=1;
            }else{
                ans--;
                break;
            }
        }
        ans++;
    }
    cout<<ans;
    return 0;
}
